string id = Request.Query["id"];
string sql = "SELECT * FROM users WHERE id = " + id;
var cmd = new SqlCommand(sql, conn);
cmd.ExecuteReader();

// UNSAFE: string interpolation is still concatenation
string email = Request.Query["email"];
