safe_example:
// SAFE: parameterized query
string id = Request.Query["id"];
var cmd = new SqlCommand("SELECT * FROM users WHERE id = @id", conn);
cmd.Parameters.AddWithValue("@id", id);
cmd.ExecuteReader();

// SAFE: typed parameters
var cmd2 = new SqlCommand("SELECT * FROM users WHERE email = @email AND active = @active", conn);
cmd2.Parameters.Add("@email", SqlDbType.NVarChar, 256).Value = email;
cmd2.Parameters.Add("@active", SqlDbType.Bit).Value = true;
